<template>
  <div class="page">

    <ul class="list-group">
      <li class="list-group-item"><h3>以下是战车的外形图</h3>
        <img src="../assets/tank1.jpg" class="img-thumbnail">
        <img src="../assets/tank2.jpg" class="img-thumbnail">
        <img src="../assets/tank3.jpg" class="img-thumbnail">
